import java.io.*;

public class InsecureDeserializationExample {

    public static void main(String[] args) {
        String userInput = "SerializedDataHere"; // Assume this is user input
        ObjectInputStream ois = null;

        try {
            // Deserialize the user input
            ByteArrayInputStream bais = new ByteArrayInputStream(userInput.getBytes());
            ois = new ObjectInputStream(bais);
            Object obj = ois.readObject();

            // Do something with the deserialized object (e.g., cast it to a known type)
            String deserializedData = (String) obj;

            System.out.println("Deserialized data: " + deserializedData);
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        } finally {
            try {
                if (ois != null) {
                    ois.close();
                }
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
    }
}

